// ── STAP 1: Haal website tekst op ──────────────────────────────────
const websiteRaw = $('Haal website op').first().json.data || '';
const websiteTekst = websiteRaw
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<!--[\s\S]*?-->/g, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 2500);

// ── STAP 2: Filter leads van gisteren ──────────────────────────────
const nu = new Date();
const gisteren = new Date(nu.getTime() - 24 * 60 * 60 * 1000);
const alleLeads = $input.all();

const leadsGisteren = alleLeads.filter(item => {
  if (!item.json.datum) return false;
  try {
    const d = new Date(item.json.datum);
    return d >= gisteren && d <= nu;
  } catch { return false; }
});

const leadsAantal = leadsGisteren.length;

const leadsTekst = leadsAantal === 0
  ? 'Geen nieuwe leads in de afgelopen 24 uur.'
  : leadsGisteren.map(l => {
      const naam    = l.json.naam    || 'Onbekend';
      const bedrijf = l.json.bedrijf || '—';
      const score   = l.json.score   || '—';
      const bericht = (l.json.bericht || '').substring(0, 120);
      return `• ${naam} (${bedrijf}) | Score: ${score}\n  "${bericht}"`;
    }).join('\n');

// ── STAP 3: Bouw Claude prompt ──────────────────────────────────────
const vandaag = nu.toLocaleDateString('nl-NL', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

const prompt = `Je bent een strategisch AI-assistent voor Doable AI.
Doable AI = automatiseringsbedrijf in Groningen voor Noord-NL MKB. Eigenaar: Vincent Smets (1 persoon).
Tagline: "Meer tijd. Minder gedoe."

Vandaag: ${vandaag}

═══ NIEUWE LEADS (afgelopen 24 uur) ═══
${leadsTekst}

═══ WEBSITE TEKST (huidig) ═══
${websiteTekst}

Geef een bondig dagrapport. Reageer UITSLUITEND met valide JSON (geen extra tekst):
{
  "samenvatting": "1–2 zinnen over de dag en wat opvalt",
  "leads": {
    "inzicht": "Wat zeggen de leads over je doelgroep of messaging? (of: geen leads → wat kun je doen?)",
    "actie": "De 1 concrete actie die Vincent vandaag kan doen m.b.t. leads"
  },
  "website_tip": {
    "sectie": "Naam van de sectie (bijv. Hero, Prijzen, Hoe het werkt)",
    "probleem": "Kort beschreven wat beter kan",
    "fix": "De exacte verbetering in 1–2 zinnen"
  },
  "seo_kans": "1 specifiek zoekwoord of content-idee voor Noord-NL MKB dat nog ontbreekt",
  "prioriteit_vandaag": "De #1 meest impactvolle actie voor Doable AI vandaag"
}`;

return [{
  json: {
    vandaag,
    leadsAantal,
    leadsTekst,
    prompt
  }
}];

// Parseer Claude response + bouw WhatsApp bericht
const raw   = $input.first().json;
const tekst = raw?.content?.[0]?.text || '{}';

let rapport = {};
try {
  const match = tekst.match(/\{[\s\S]*\}/);
  rapport = match ? JSON.parse(match[0]) : {};
} catch {
  rapport = { samenvatting: tekst.substring(0, 200), prioriteit_vandaag: '— (parse fout, check n8n logs)' };
}

const vandaag     = $('Bereid Claude prompt').first().json.vandaag;
const leadsAantal = $('Bereid Claude prompt').first().json.leadsAantal;
const leadsTekst  = $('Bereid Claude prompt').first().json.leadsTekst;

// Bouw het WhatsApp bericht (max ~1500 tekens)
const regels = [
  `🤖 *Doable AI — Dagrapport*`,
  `📅 ${vandaag}`,
  ``,
  `📋 *Samenvatting*`,
  rapport.samenvatting || '—',
  ``,
  `👥 *Leads (${leadsAantal} nieuw)*`,
  rapport.leads?.inzicht || '—',
  rapport.leads?.actie ? `💡 Actie: ${rapport.leads.actie}` : '',
  ``,
  `🌐 *Website tip — ${rapport.website_tip?.sectie || '?'}*`,
  rapport.website_tip?.probleem || '—',
  rapport.website_tip?.fix ? `✅ Fix: ${rapport.website_tip.fix}` : '',
  ``,
  `🔍 *SEO kans*`,
  rapport.seo_kans || '—',
  ``,
  `⚡ *Prioriteit vandaag*`,
  rapport.prioriteit_vandaag || '—',
];

